import React from 'react';
import { MessageCircle } from 'lucide-react';

const AssistantPage = () => {
    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center px-4">
            <div className="bg-purple-50 p-6 rounded-full text-purple-600 mb-6">
                <MessageCircle size={48} />
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">AI Health Assistant</h1>
            <p className="text-gray-600 max-w-md">
                Chat with our advanced AI to get answers to your health questions.
                <br />
                <span className="text-sm font-semibold text-purple-600 mt-2 block">Coming Soon</span>
            </p>
        </div>
    );
};

export default AssistantPage;
